int getbit(int state, int i) {return ((state>>i)&1);}



int n;

long long ans[N+5];

ii a[N+5];

bool cmp(ii X, ii Y)

{

    if (X.fs!=Y.fs) return X.fs>Y.fs;

    return X.sd<Y.sd;

}

int main()

{

	//freopen("Frequency.inp","r",stdin);

	//freopen("Frequency.out","w",stdout);

